class Solution:
    def minimumDifference(self, nums: List[int], k: int) -> int:
        min_diff = float('inf')
        n = len(nums)
        or_set = set()

        for i in range(n):
            new_or_set = set()
            for num in or_set:
                new_or_set.add(num | nums[i])
            new_or_set.add(nums[i])
            or_set = new_or_set
            for val in or_set:
                min_diff = min(min_diff, abs(val - k))

        return min_diff
